  ('heelevel3-e9ff7ca9-moex-00249', 'heelevel3-e9ff7ca9', 'heelevel3-e9ff7ca9-moex-111-3082b5f1', 'sub-heelevel3-e9ff7ca9-04', NULL, 'single_choice', '依行政程序法規定，授予利益行政處分之廢止，下列敘述何者正確？', '["廢止，應自廢止原因發生後3年內為之", "行政處分經廢止後，溯及既往失其效力", "行政處分得由原處分機關依職權為全部或一部之廢止", "行政處分之廢止，於補償受益人財產上之損失後始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:47+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "303", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "客家事務行政"}'::jsonb, NULL),
