  ('heelevel3-e9ff7ca9-moex-00251', 'heelevel3-e9ff7ca9', 'heelevel3-e9ff7ca9-moex-111-3082b5f1', 'sub-heelevel3-e9ff7ca9-04', NULL, 'single_choice', '依實務見解，關於公法上金錢給付義務人死亡後之行政執行，下列敘述何者正確？', '["納稅義務人死亡後，其納稅能力消滅，無須再予以徵繳", "行政機關課以義務人履行公法上義務之怠金，具有一身專屬性，不得由繼承人繼承", "罰鍰義務人死亡後，仍得就其遺產，進行行政執行", "行政法院依法律規定，就公法上金錢給付義務，僅得依民事執行程序，為假扣押、假處分之裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:47+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "303", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('heelevel3-e9ff7ca9-moex-00252', 'heelevel3-e9ff7ca9', 'heelevel3-e9ff7ca9-moex-111-3082b5f1', 'sub-heelevel3-e9ff7ca9-04', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["甲飲酒駕駛汽車，為警攔查，發現其吐氣酒精濃度超過規定標準，經裁罰新臺幣10萬元；而涉 刑事犯罪部分，另經法院判處罰金新臺幣3萬元，基於從輕原則，監理機關依法不可事後再裁 決命甲補繳納新臺幣7萬元", "行政罰之裁處權時效，因天災、事變或依法律規定不能開始或進行裁處時，應停止其進行", "乙同一行為違反同一行政法上義務，A、B機關均有管轄權，因A機關處理在先，因此依法應 由A機關管轄該案件", "行政機關執行行政罰職務之人員，應向違反行政法規定之行為人出示其執行職務之證明文件， 並告知其所違反之法規"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:47+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "303", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('heelevel3-e9ff7ca9-moex-00253', 'heelevel3-e9ff7ca9', 'heelevel3-e9ff7ca9-moex-111-3082b5f1', 'sub-heelevel3-e9ff7ca9-04', NULL, 'single_choice', '行政執行法有關行政執行即時強制之規定，下列敘述何者錯誤？', '["對於執行機關所為損失補償之決定不服者，得依法提起國家賠償", "軍器、凶器及其他危險物，為預防危害之必要，得扣留之", "對於住宅、建築物或其他處所之進入，以人民之生命、身體、財產有迫切之危害，非進入不能 救護者為限", "人民因執行機關依法實施即時強制，致其生命、身體或財產遭受特別損失時，得請求補償 31350、31450 32050、32750 32850 33550"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:47+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "303", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "客家事務行政"}'::jsonb, NULL),
